import { loadTestConfig } from '../loadtest.config.js';

type NumericMetric = {
  actual: number;
  max?: number;
  min?: number;
  label: string;
};

export type LoadTestValidationInput = {
  requestsPerSecond?: number;
  non2xx?: number;
  errors?: number;
  timeouts?: number;
  totalRequests?: number;
  latencyP50?: number;
  latencyP95?: number;
  latencyP99?: number;
  duration?: string;
  connections?: number;
  chatTurn?: number;
  fleetGraphThreadCreates?: number;
  fleetGraphThreadReuses?: number;
};

export type LoadTestValidationResult = {
  passed: boolean;
  failures: string[];
  summary: {
    totalRequests: number | null;
    failedRequests: number | null;
    failedRequestRate: number | null;
    requestsPerSecond: number | null;
    latencyP50: number | null;
    latencyP95: number | null;
    latencyP99: number | null;
  };
};

const percent = (value: number) => `${(value * 100).toFixed(2)}%`;

const assertMetric = ({ actual, max, min, label }: NumericMetric, failures: string[]) => {
  if (typeof min === 'number' && actual < min) {
    failures.push(`${label} must be >= ${min}, received ${actual}`);
  }
  if (typeof max === 'number' && actual > max) {
    failures.push(`${label} must be <= ${max}, received ${actual}`);
  }
};

export const validateLoadTestResult = (input: LoadTestValidationInput): LoadTestValidationResult => {
  const failures: string[] = [];
  const totalRequests = input.totalRequests ?? null;
  const failedRequests = (input.non2xx ?? 0) + (input.errors ?? 0) + (input.timeouts ?? 0);
  const failedRequestRate = totalRequests && totalRequests > 0 ? failedRequests / totalRequests : null;

  const rpsTarget = loadTestConfig.profile === 'baseline' ? 10 : 0;
  const latencyTargetP95Ms = 2000;
  const latencyTargetP99Ms = 5000;
  const acceptableFailureRate = 0.01;

  if (typeof input.requestsPerSecond === 'number') {
    assertMetric({ actual: input.requestsPerSecond, min: rpsTarget, label: 'requestsPerSecond' }, failures);
  }
  if (typeof input.latencyP95 === 'number') {
    assertMetric({ actual: input.latencyP95, max: latencyTargetP95Ms, label: 'latencyP95' }, failures);
  }
  if (typeof input.latencyP99 === 'number') {
    assertMetric({ actual: input.latencyP99, max: latencyTargetP99Ms, label: 'latencyP99' }, failures);
  }
  if (typeof failedRequestRate === 'number' && failedRequestRate > acceptableFailureRate) {
    failures.push(`failed request rate must be <= ${percent(acceptableFailureRate)}, received ${percent(failedRequestRate)}`);
  }

  if (typeof input.chatTurn === 'number' && input.chatTurn < 1) {
    failures.push('chatTurn must be at least 1 for a canonical Task 2 run');
  }
  if (typeof input.fleetGraphThreadCreates === 'number' && input.fleetGraphThreadCreates < 1) {
    failures.push('fleetGraphThreadCreates must be at least 1 for a canonical Task 2 run');
  }
  if (typeof input.fleetGraphThreadReuses === 'number' && input.fleetGraphThreadReuses < 1) {
    failures.push('fleetGraphThreadReuses must be at least 1 for a canonical Task 2 run');
  }

  if (typeof input.duration === 'string' && input.duration.trim() === '') {
    failures.push('duration must not be empty');
  }
  if (typeof input.connections === 'number' && input.connections <= 0) {
    failures.push('connections must be positive');
  }

  return {
    passed: failures.length === 0,
    failures,
    summary: {
      totalRequests,
      failedRequests: failedRequests ?? null,
      failedRequestRate,
      requestsPerSecond: input.requestsPerSecond ?? null,
      latencyP50: input.latencyP50 ?? null,
      latencyP95: input.latencyP95 ?? null,
      latencyP99: input.latencyP99 ?? null,
    },
  };
};

export const formatLoadTestValidationReport = (result: LoadTestValidationResult) => {
  const lines = [
    `Load test validation: ${result.passed ? 'PASS' : 'FAIL'}`,
    `Total requests: ${result.summary.totalRequests ?? 'n/a'}`,
    `Failed requests: ${result.summary.failedRequests ?? 'n/a'}`,
    `Failed request rate: ${result.summary.failedRequestRate == null ? 'n/a' : percent(result.summary.failedRequestRate)}`,
    `Requests/sec: ${result.summary.requestsPerSecond ?? 'n/a'}`,
    `Latency P50/P95/P99: ${result.summary.latencyP50 ?? 'n/a'} / ${result.summary.latencyP95 ?? 'n/a'} / ${result.summary.latencyP99 ?? 'n/a'}`,
  ];

  if (result.failures.length > 0) {
    lines.push('Failures:');
    for (const failure of result.failures) {
      lines.push(`- ${failure}`);
    }
  }

  return lines.join('\n');
};

import { describe, expect, it } from 'vitest';
import { formatLoadTestValidationReport, validateLoadTestResult } from './loadtest.validation.js';

describe('loadtest validation helpers', () => {
  it('passes a canonical baseline run with healthy metrics', () => {
    const result = validateLoadTestResult({
      requestsPerSecond: 12,
      non2xx: 0,
      errors: 0,
      timeouts: 0,
      totalRequests: 1000,
      latencyP50: 120,
      latencyP95: 1800,
      latencyP99: 4200,
      duration: '15m',
      connections: 10,
      chatTurn: 3,
      fleetGraphThreadCreates: 1,
      fleetGraphThreadReuses: 1,
    });

    expect(result.passed).toBe(true);
    expect(result.failures).toHaveLength(0);
    expect(formatLoadTestValidationReport(result)).toContain('PASS');
  });

  it('flags slow or error-prone runs', () => {
    const result = validateLoadTestResult({
      requestsPerSecond: 6,
      non2xx: 4,
      errors: 1,
      timeouts: 0,
      totalRequests: 100,
      latencyP50: 250,
      latencyP95: 4500,
      latencyP99: 9000,
      duration: '15m',
      connections: 10,
      chatTurn: 0,
      fleetGraphThreadCreates: 0,
      fleetGraphThreadReuses: 0,
    });

    expect(result.passed).toBe(false);
    expect(result.failures.length).toBeGreaterThan(0);
    expect(result.failures.join('\n')).toContain('failed request rate');
    expect(result.failures.join('\n')).toContain('latencyP95');
    expect(formatLoadTestValidationReport(result)).toContain('FAIL');
  });
});
